class Solution:
    def countServers(self, grid):
        m, n = len(grid), len(grid[0])
        count = 0
        for r in range(m):
            for c in range(n):
                if grid[r][c] == 1:
                    # brute-force: scan entire row and column for any other server
                    communicates = False
                    for cc in range(n):
                        if cc != c and grid[r][cc] == 1:
                            communicates = True
                            break
                    if not communicates:
                        for rr in range(m):
                            if rr != r and grid[rr][c] == 1:
                                communicates = True
                                break
                    if communicates:
                        count += 1
        return count

