class Solution:
    def countServers(self, grid):
        m, n = len(grid), len(grid[0])
        row_count = [0] * m
        col_count = [0] * n
        for r in range(m):
            for c in range(n):
                if grid[r][c]:
                    row_count[r] += 1
                    col_count[c] += 1
        total = 0
        for r in range(m):
            for c in range(n):
                if grid[r][c] and (row_count[r] > 1 or col_count[c] > 1):
                    total += 1
        return total

